// Purpose: Build the daily run context and validate required environment variables.
const crypto = require('crypto');

const account = $env.GMAIL_ACCOUNT || 'primary';
const runId = crypto.randomUUID();
const runDate = new Date().toISOString().slice(0, 10);
const executionId = String($execution.id);
const workflowName = 'Shiny Gmail Daily Orchestrator V2.6 Lean';

const required = ['GMAIL_ACCOUNT', 'GEMINI_API_KEY', 'TELEGRAM_CHAT_ID'];
const missing = required.filter(k => !$env[k]);

return [{
  json: {
    account,
    runId,
    runDate,
    executionId,
    workflowName,
    envOk: missing.length === 0,
    missingEnv: missing,
    runStatus: missing.length > 0 ? 'failed' : 'running',
    failureStage: missing.length > 0 ? 'env_validation' : null,
    errorMessage: missing.length > 0 ? `Missing required env vars: ${missing.join(', ')}` : null,
    requiredLabels: ['unimportant','receipts','priority','email-subs','please-review','processed'],
    startedAt: new Date().toISOString(),
    runStarted: false
  }
}];

// Purpose: Evaluate whether another recent run is already active.
// V2.6: Guard failure conservatively assumes active run (fail-safe, not fail-open).
const ctx = $('Build Context And Validate Env').first()?.json || {};
const row = $input.first()?.json || {};

if (row.error) {
  return [{
    json: {
      ...ctx,
      guardFailed: true,
      activeRun: true,
      runStatus: 'failed',
      failureStage: 'run_guard_query',
      errorMessage: row.error?.message || 'Run guard query failed. Skipping as precaution.',
      runStarted: false
    }
  }];
}

const activeRun = Boolean(row.run_id);

return [{
  json: {
    ...ctx,
    activeRun,
    activeRunId: row.run_id || null,
    activeRunStartedAt: row.started_at || null,
    runStatus: activeRun ? 'skipped_active_run' : 'running',
    failureStage: activeRun ? 'active_run_guard' : null,
    errorMessage: activeRun ? `Skipped because another run is active: ${row.run_id}` : ctx.errorMessage,
    runStarted: false
  }
}];

// Purpose: Validate required Gmail labels and build labelMap for child workflow.
const baseCtx = $('Evaluate Run Guard').first()?.json || $('Build Context And Validate Env').first()?.json || {};
const first = $input.first()?.json || {};

if (first.error) {
  return [{
    json: {
      ...baseCtx,
      runStarted: true,
      labelsOk: false,
      runStatus: 'failed',
      failureStage: 'gmail_label_fetch',
      errorMessage: first.error?.message || 'Failed to fetch Gmail labels.',
      labelMap: {}
    }
  }];
}

const labels = $input.all().map(i => i.json || {}).filter(l => l.id && l.name);
const labelMap = {};

for (const label of labels) {
  const name = String(label.name || '').toLowerCase();
  if ((baseCtx.requiredLabels || []).includes(name)) labelMap[name] = label.id;
}

const missing = (baseCtx.requiredLabels || []).filter(l => !labelMap[l]);

return [{
  json: {
    ...baseCtx,
    runStarted: true,
    labelsOk: missing.length === 0,
    missingLabels: missing,
    labelMap,
    processedLabelId: labelMap.processed || null,
    runStatus: missing.length ? 'failed' : 'running',
    failureStage: missing.length ? 'gmail_label_validation' : null,
    errorMessage: missing.length ? `Missing Gmail labels: ${missing.join(', ')}` : null
  }
}];

// Purpose: Pack many sender-rule rows into one item so Fetch Inbox Emails runs exactly once.
const ctx = $('Validate Labels And Build Map').first()?.json || {};
const rows = $input.all().map(i => i.json || {});
const failed = rows.some(r => r.error);
const errorRow = rows.find(r => r.error);

return [{
  json: {
    ...ctx,
    rulesFailed: failed,
    rulesError: failed ? (errorRow?.error?.message || 'Failed to load sender rules.') : null,
    senderRules: failed ? [] : rows.filter(r => r.sender_pattern && r.rule_type)
  }
}];

// Purpose: Normalize Gmail search results into one child-processing item per email.
// V2.6: Same-run dedup by email.id + subdomain matching for domain rules.
const ctx = $('Pack Sender Rules').first()?.json || $('Validate Labels And Build Map').first()?.json || {};
const packedRules = $('Pack Sender Rules').first()?.json || {};
const rulesFailed = Boolean(packedRules.rulesFailed);
const rules = packedRules.senderRules || [];

const inboxItems = $input.all().map(i => i.json || {});
const inboxFailed = inboxItems.some(e => e.error);

if (rulesFailed) {
  return [{
    json: {
      ...ctx,
      noWork: true,
      runStatus: 'failed',
      failureStage: 'sender_rules_load',
      totalDiscovered: 0,
      errorMessage: packedRules.rulesError || 'Failed to load sender rules.'
    }
  }];
}

if (inboxFailed) {
  return [{
    json: {
      ...ctx,
      noWork: true,
      runStatus: 'failed',
      failureStage: 'gmail_inbox_fetch',
      totalDiscovered: 0,
      errorMessage: inboxItems.find(e => e.error)?.error?.message || 'Failed to fetch inbox emails.'
    }
  }];
}

const rawEmails = inboxItems.filter(e => e.id);

// Deduplicate by email.id to prevent duplicate loop iterations
const seen = new Map();
for (const email of rawEmails) {
  if (!seen.has(email.id)) seen.set(email.id, email);
}
const uniqueEmails = Array.from(seen.values());

function getHeader(e, k) {
  const h = e.headers || e.payload?.headers || [];
  const f = h.find(x => String(x.name || '').toLowerCase() === k.toLowerCase());
  return f?.value || '';
}

function extractEmail(r) {
  const s = String(r || '').toLowerCase();
  const m = s.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/i);
  return m ? m[0].toLowerCase() : s.trim();
}

function domainOf(s) {
  return String(s || '').split('@')[1] || '';
}

function matchRule(sender, rules) {
  const domain = domainOf(sender);
  for (const r of rules) {
    const pattern = String(r.sender_pattern || '').toLowerCase().trim();
    const matchType = String(r.match_type || 'exact_sender').toLowerCase();
    if (matchType === 'exact_sender' && sender === pattern) return r;
    const p = pattern.replace(/^@/, '');
    if (matchType === 'domain' && (domain === p || domain.endsWith('.' + p))) return r;
  }
  return null;
}

function ruleToCategory(rule) {
  if (!rule) return null;
  const t = String(rule.rule_type || '').toLowerCase();
  if (t === 'whitelist') return 'priority';
  if (t === 'blacklist') return 'unimportant';
  if (t === 'force_receipts') return 'receipts';
  if (t === 'force_review') return 'please-review';
  return null;
}

function ruleToSource(rule) {
  if (!rule) return 'ai';
  const matchType = String(rule.match_type || 'exact_sender').toLowerCase();
  const ruleType = String(rule.rule_type || '').toLowerCase();
  if (matchType === 'domain' && ruleType === 'whitelist') return 'domain_whitelist';
  if (matchType === 'domain' && ruleType === 'blacklist') return 'domain_blacklist';
  return ruleType;
}

if (!uniqueEmails.length) {
  return [{
    json: {
      ...ctx,
      noWork: true,
      runStatus: 'completed',
      failureStage: null,
      totalDiscovered: 0,
      totalCompleted: 0,
      totalFailed: 0,
      totalSkipped: 0,
      totalReview: 0
    }
  }];
}

return uniqueEmails.map(email => {
const fromRaw = email.From || email.from || getHeader(email, 'from');
const sender = extractEmail(fromRaw);
const subject = email.Subject || email.subject || getHeader(email, 'subject') || '(no subject)';
const snippet = email.snippet || '';
const messageId = email.id;
const threadId = email.threadId || '';
const date = email.Date || email.date || getHeader(email, 'date') || '';
  const matchedRule = matchRule(sender, rules);
  const ruleCategory = ruleToCategory(matchedRule);
  const requiresGemini = !ruleCategory;

  return {
    json: {
      account: ctx.account,
      runId: ctx.runId,
      runDate: ctx.runDate,
      executionId: ctx.executionId,
      workflowName: ctx.workflowName,
      messageId,
      threadId,
      sender,
      fromRaw,
      subject,
      snippet,
      date,
      labelMap: ctx.labelMap,
      processedLabelId: ctx.processedLabelId,
      matchedRule: matchedRule || null,
      category: ruleCategory || null,
      source: ruleCategory ? ruleToSource(matchedRule) : 'ai',
      confidence: ruleCategory ? 1 : null,
      reasoning: ruleCategory ? `Matched sender rule: ${matchedRule.rule_type}.` : null,
      requiresGemini,
      noWork: false,
      totalDiscovered: uniqueEmails.length
    }
  };
});

// V2.6: Added failureStage for child crashes.
const input = $input.first()?.json || {};
if (input.error) {
  const current = $('Split Emails').first()?.json || {};
  return [{
    json: {
      status: 'failed',
      messageId: current.messageId || null,
      category: current.category || null,
      source: current.source || 'child_error',
      reasoning: current.reasoning || null,
      confidence: current.confidence ?? 0,
      failureStage: 'child_execution_failed',
      errorMessage: input.error?.message || 'Child workflow execution failed.',
      ledgerWarning: false
    }
  }];
}
return [{ json: input }];

// Purpose: Aggregate loop results from the SplitInBatches done output.
// V2.6: Uses $input.all() + propagated totalDiscovered + zero-results guard.
function safeNode(name) {
  try { return $(name).first()?.json || null; } catch (e) { return null; }
}

const ctx = safeNode('Validate Labels And Build Map') || safeNode('Build Context And Validate Env') || {};
const results = $input.all().map(i => i.json || {});

if (!results.length) {
  return [{
    json: {
      ...ctx,
      runStatus: 'completed_empty_loop',
      failureStage: null,
      totalDiscovered: ctx.totalDiscovered ?? 0,
      totalCompleted: 0,
      totalFailed: 0,
      totalSkipped: 0,
      totalReview: 0,
      ledgerWarnings: 0,
      aiFailedCount: 0,
      failedDetails: [],
      errorMessage: null
    }
  }];
}

const discovered = results[0]?.totalDiscovered ?? results.length;

const totalCompleted = results.filter(r => r.status === 'completed').length;
const totalFailed = results.filter(r => r.status === 'failed').length;
const totalSkipped = results.filter(r => r.status === 'skipped').length;
const totalReview = results.filter(r => r.category === 'please-review').length;
const ledgerWarnings = results.filter(r => r.ledgerWarning).length;
const aiFailedCount = results.filter(r => r.source === 'ai_failed').length;
const runStatus = totalFailed > 0 ? 'completed_with_failures' : 'completed';

return [{
  json: {
    ...ctx,
    runStatus,
    failureStage: null,
    totalDiscovered: discovered,
    totalCompleted,
    totalFailed,
    totalSkipped,
    totalReview,
    ledgerWarnings,
    aiFailedCount,
    failedDetails: results.filter(r => r.status === 'failed').slice(0, 10).map(r => ({ messageId: r.messageId, error: r.errorMessage })),
    errorMessage: totalFailed > 0 ? `${totalFailed} email(s) failed during processing.` : null
  }
}];

// Purpose: Normalize all non-processing exits into one daily summary shape.
function safeNode(name) {
  try { return $(name).first()?.json || null; } catch (e) { return null; }
}

const incoming = $json || {};
const fallbackCtx = safeNode('Validate Labels And Build Map') || safeNode('Evaluate Run Guard') || safeNode('Build Context And Validate Env') || {};
const ctx = { ...fallbackCtx, ...incoming };

const incomingError = incoming.error?.message || incoming.errorMessage || null;
const finalError = incomingError || ctx.errorMessage || null;
const finalStatus = finalError ? 'failed' : (ctx.runStatus || 'completed');

return [{
  json: {
    ...ctx,
    runStatus: finalStatus,
    failureStage: ctx.failureStage || (finalError ? 'summary_convergence' : null),
    totalDiscovered: ctx.totalDiscovered || 0,
    totalCompleted: ctx.totalCompleted || 0,
    totalFailed: ctx.totalFailed || 0,
    totalSkipped: ctx.totalSkipped || 0,
    totalReview: ctx.totalReview || 0,
    ledgerWarnings: ctx.ledgerWarnings || 0,
    aiFailedCount: ctx.aiFailedCount || 0,
    errorMessage: finalError,
    skipMarkFinished: !ctx.runStarted || ctx.runStatus === 'skipped_active_run'
  }
}];

// Purpose: Format the daily run summary for Telegram notification.
// V2.6: Error message sanitization to prevent credential leakage.
function safeNode(name) {
  try { return $(name).first()?.json || null; } catch (e) { return null; }
}
function h(s) { return String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
function tg(s) { s = String(s ?? ''); return s.length <= 3900 ? s : s.slice(0, 3900) + '\n\n[...truncated]'; }
function sanitize(s) {
  if (!s) return s;
  return String(s)
    .replace(/postgres(?:ql)?:\/\/[^\s]+/gi, '[REDACTED_URL]')
    .replace(/(?:api[_-]?key|token|secret|password|credential)[s]?\s*[=:]\s*\S+/gi, '[REDACTED]');
}

const summary = safeNode('Build Final Summary') || safeNode('Build No Work Summary') || safeNode('Evaluate Run Guard') || safeNode('Build Context And Validate Env') || {};
const db = $input.first()?.json || {};
const dbError = sanitize(db.error?.message || null);
const status = db.status || summary.runStatus || 'completed';
const icon = (Number(summary.totalFailed || 0) > 0 || String(status).includes('failed') || dbError) ? '⚠️' : '✅';

const reviewAlert = Number(summary.totalReview || 0) > 0 ? `\n🔔 <b>${Number(summary.totalReview || 0)} email(s) need your review.</b>` : '';
const ledgerNote = Number(summary.ledgerWarnings || 0) > 0 ? `\nLedger warnings: ${Number(summary.ledgerWarnings || 0)} email(s) processed but ledger update had warnings.` : '';
const aiFailedNote = Number(summary.aiFailedCount || 0) > 0 ? `\nAI fallback: ${Number(summary.aiFailedCount || 0)} email(s) routed safely to please-review.` : '';
const finalizationNote = dbError ? `\nRun summary DB update failed: ${h(dbError)}` : '';
const failureStage = summary.failureStage ? `\nFailure stage: ${h(sanitize(summary.failureStage))}` : '';
const started = summary.startedAt ? `\nStarted: ${h(summary.startedAt)}` : '';
const footer = `\n\nExecution ID: ${h(summary.executionId || 'unknown')}`;

const text = `${icon} <b>🧹 Shiny Gmail Daily Run</b>\n\nAccount: ${h(summary.account)}\nStatus: ${h(status)}\nEmails found: ${Number(summary.totalDiscovered || 0)}\nCompleted: ${Number(summary.totalCompleted || 0)}\nSkipped: ${Number(summary.totalSkipped || 0)}\nPlease-review: ${Number(summary.totalReview || 0)}\nFailures: ${Number(summary.totalFailed || 0)}${reviewAlert}${ledgerNote}${aiFailedNote}${finalizationNote}${failureStage}${started}\n\n${Number(summary.totalDiscovered || 0) === 0 ? 'Nothing to clean today.' : 'Daily Gmail cleanup finished.'}${summary.errorMessage ? `\n\nNote: ${h(sanitize(summary.errorMessage))}` : ''}${footer}`;

return [{ json: { ...summary, text: tg(text) } }];
